def utc_now() -> str:
    return dt.datetime.now(dt.timezone.utc).isoformat()


def ensure_iso_ts(ts: Optional[Union[str, float, int]]) -> str:
    if ts is None:
        return utc_now()
    if isinstance(ts, (int, float)):
        return dt.datetime.fromtimestamp(float(ts), tz=dt.timezone.utc).isoformat()
    s = str(ts).strip()
    if s.isdigit():
        return dt.datetime.fromtimestamp(float(s), tz=dt.timezone.utc).isoformat()
    return s


def month_suffix(ts_iso: str) -> str:
    try:
        d = dt.datetime.fromisoformat(ts_iso.replace("Z", "+00:00"))
    except Exception:
        d = dt.datetime.now(dt.timezone.utc)
    return d.strftime("%Y.%m")


