def _print_json(data: Any) -> None:
    print(json.dumps(data, indent=2, ensure_ascii=False, default=str))


def build_parser() -> argparse.ArgumentParser:
    p = argparse.ArgumentParser(prog="es_app", description="Centralized logging and full-text search using Elasticsearch.")
    p.add_argument("--es", default=DEFAULT_ES_URL, help="Elasticsearch URL (default: http://localhost:9200)")
    p.add_argument("--timeout", type=float, default=DEFAULT_TIMEOUT, help="Request timeout seconds")
    p.add_argument("--user", default=os.getenv("ES_USER"), help="Basic auth user")
    p.add_argument("--pass", dest="password", default=os.getenv("ES_PASS"), help="Basic auth password")
    sub = p.add_subparsers(dest="cmd", required=True)

    sub.add_parser("ping", help="Ping Elasticsearch cluster")

    idx = sub.add_parser("index-doc", help="Index a document into docs index")
    idx.add_argument("--index", default=DEFAULT_DOC_INDEX)
    idx.add_argument("--id", default=None)
    idx.add_argument("--title", default=None)
    idx.add_argument("--body", default=None)
    idx.add_argument("--tags", nargs="*", default=None)
    idx.add_argument("--source", default=None)
    idx.add_argument("--meta", nargs="*", default=[], help="Meta key=val pairs")
    idx.add_argument("--json", dest="json_doc", default=None, help="Raw JSON document string")
    idx.add_argument("--refresh", default=None, help="Refresh (true/false/wait_for)")

    s = sub.add_parser("search", help="Run a full-text search")
    s.add_argument("--index", default=f"{DEFAULT_DOC_INDEX},{DEFAULT_LOG_INDEX_PREFIX}-*")
    s.add_argument("query")
    s.add_argument("--fields", nargs="*", default=None)
    s.add_argument("--filter", nargs="*", default=[], help="Filter key=val pairs (term/terms)")
    s.add_argument("--size", type=int, default=10)
    s.add_argument("--from", dest="from_", type=int, default=0)
    s.add_argument("--sort", default=None)
    s.add_argument("--highlight", action="store_true")

    le = sub.add_parser("log", help="Write a log event to logs data stream")
    le.add_argument("message")
    le.add_argument("--level", default="INFO")
    le.add_argument("--service", default="app")
    le.add_argument("--env", default="default")
    le.add_argument("--dataset", default="app")
    le.add_argument("--namespace", default="default")
    le.add_argument("--ts", default=None, help="Timestamp (ISO8601 or epoch seconds)")
    le.add_argument("--trace-id", default=None)
    le.add_argument("--span-id", default=None)
    le.add_argument("--logger", default=None)
    le.add_argument("--thread", default=None)
    le.add_argument("--exception", default=None)
    le.add_argument("--field", nargs="*", default=[], help="Extra fields key=val pairs")
    le.add_argument("--refresh", default=None, help="Refresh (true/false/wait_for)")

    ag = sub.add_parser("aggregate-logs", help="Aggregate logs (counts by level/service/host/logger + timeline)")
    ag.add_argument("--index", default=f"{DEFAULT_LOG_INDEX_PREFIX}-*")
    ag.add_argument("--start", default=None, help="Start time (ISO8601)")
    ag.add_argument("--end", default=None, help="End time (ISO8601)")
    ag.add_argument("--service", default=None)
    ag.add_argument("--env", default=None)
    ag.add_argument("--level", default=None)
    ag.add_argument("--interval", default="1h")
    ag.add_argument("--q", default=None, help="Optional query string to filter messages")
    ag.add_argument("--top-services", type=int, default=10)
    ag.add_argument("--top-hosts", type=int, default=10)
    ag.add_argument("--top-loggers", type=int, default=10)

    tl = sub.add_parser("tail-logs", help="Tail logs continuously")
    tl.add_argument("--index", default=f"{DEFAULT_LOG_INDEX_PREFIX}-*")
    tl.add_argument("--q", default=None)
    tl.add_argument("--service", default=None)
    tl.add_argument("--env", default=None)
    tl.add_argument("--level", default=None)
    tl.add_argument("--poll", type=float, default=1.0)
    tl.add_argument("--size", type=int, default=50)

    return p


def main(argv: Optional[List[str]] = None) -> int:
    args = build_parser().parse_args(argv)

    cfg = ESConfig(
        url=args.es,
        request_timeout=args.timeout,
        basic_auth_user=args.user,
        basic_auth_pass=args.password,
    )
    app = ESApp(cfg)

    if args.cmd == "ping":
        ok = app.ping()
        _print_json({"ok": ok})
        return 0 if ok else 2

    if args.cmd == "index-doc":
        if args.json_doc:
            doc = json.loads(args.json_doc)
        else:
            doc = {}
            if args.title is not None:
                doc["title"] = args.title
            if args.body is not None:
                doc["body"] = args.body
            if args.tags is not None:
                doc["tags"] = args.tags
            if args.source is not None:
                doc["source"] = args.source
            meta = parse_kv_pairs(args.meta)
            if meta:
                doc["meta"] = meta
        resp = app.index_document(index=args.index, doc=doc, doc_id=args.id, refresh=args.refresh)
        _print_json(resp)
        return 0

    if args.cmd == "search":
        filters = parse_kv_pairs(args.filter)
        resp = app.search(
            index=args.index,
            query=args.query,
            fields=args.fields,
            filters=filters,
            size=args.size,
            from_=args.from_,
            sort=args.sort,
            highlight=args.highlight,
        )
        _print_json(resp)
        return 0

    if args.cmd == "log":
        fields = parse_kv_pairs(args.field)
        resp = app.log_event(
            message=args.message,
            level=args.level,
            service=args.service,
            env=args.env,
            dataset=args.dataset,
            namespace=args.namespace,
            timestamp=args.ts,
            trace_id=args.trace_id,
            span_id=args.span_id,
            logger=args.logger,
            thread=args.thread,
            exception=args.exception,
            fields=fields or None,
            refresh=args.refresh,
        )
        _print_json(resp)
        return 0

    if args.cmd == "aggregate-logs":
        resp = app.aggregate_logs(
            index=args.index,
            start=args.start,
            end=args.end,
            service=args.service,
            env=args.env,
            level=args.level,
            interval=args.interval,
            top_services=args.top_services,
            top_hosts=args.top_hosts,
            top_loggers=args.top_loggers,
            query=args.q,
        )
        _print_json(resp)
        return 0

    if args.cmd == "tail-logs":
        app.tail_logs(
            index=args.index,
            query=args.q,
            service=args.service,
            env=args.env,
            level=args.level,
            poll_interval=args.poll,
            size=args.size,
        )
        return 0

    return 2


if __name__ == "__main__":
    raise SystemExit(main())